    r5na.append(fit_score(rich5_noamp, X, y, [14.0, 9e-4, 0.001, 0.3, 0.0]))
    r5nx.append(fit_score(rich5_nox1, X, y, [1.0, 14.0, 9e-4, 0.3, 0.0]))

