print(f'Rich5 no-amp (c19): mean_nmse={np.mean(r5na):.4f} combined={combined(np.mean(r5na),19):.4f}')
print(f'Rich5 no-x1  (c17): mean_nmse={np.mean(r5nx):.4f} combined={combined(np.mean(r5nx),17):.4f}')
